var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"헉…… 헉…… 쓰러트렸나?","JPN":"はあ……はあ……倒したか？","ENG":"*Huff... Huff...* Is he dead?","TWN":"呼……呼…… 倒下了？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이건……? 피가 담긴 주사기?","JPN":"これは……？　血が入った注射器？","ENG":"Wait... A syringe with blood?","TWN":"這是……？針筒的裡面是血？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"놈들이 나에게 한 실험을 하바키에게도 저지른 건가?","JPN":"奴らが私にした実験を覇吐にもしたのか？","ENG":"The experiment they conducted on me... Did they also do it to Habaki?","TWN":"他們也對幅木進行和我一樣的實驗嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"<color=#ff3636>나나하라…… 치후유……</color>","JPN":"<color=#ff3636>七原……千冬……</color>","ENG":"<color=#ff3636>Nanahara... Chifuyu...</color>","TWN":"<color=#ff3636>七原…… 千冬……</color>"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"<color=#ff3636>너를…… 역신이 되게 두진…… 않…… 겠다……!</color>","JPN":"<color=#ff3636>お前を……疫病神になるように……しておきは……しない……！</color>","ENG":"<color=#ff3636>I... will not let... you... become... a Plague God...!</color>","TWN":"<color=#ff3636>我……不會……讓你成為……瘟神……！</color>"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"마지막까지…… 말도 안 되는 헛소리를……!","JPN":"最後まで……何をたわけたことを……！","ENG":"Until the end... He keeps spouting this nonsense...!","TWN":"死到臨頭……還在胡說八道什麼……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"큿, 팔이…… 안 움직여?","JPN":"くっ、腕が……動かない？","ENG":"Kgh...! My arm... I cannot move it...","TWN":"唔，我的手臂……沒辦法動？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"아니……?!","JPN":"あ……！？","ENG":"Huh...?!","TWN":"怎麼會……？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"배반자에 어울리는 추악한 꼬락서니구나, 하바키.","JPN":"裏切り者に相応しい醜い様だな、覇吐。","ENG":"A befitting end for a traitor like you, Habaki.","TWN":"看你這副狼狽樣，幅木，這就是叛徒的下場。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"<color=#ff3636>사나에……</color>","JPN":"<color=#ff3636>早苗……</color>","ENG":"<color=#ff3636>Sanae...</color>","TWN":"<color=#ff3636>早苗……</color>"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_27"},{"id":"L20_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"<color=#ff3636>사나에-----!!!!!</color>","JPN":"<color=#ff3636>早苗ーーーー！！！！！</color>","ENG":"<color=#ff3636>SANAE!!!!!</color>","TWN":"<color=#ff3636>早苗-----！！！！！</color>"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_30"},{"id":"L21_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"더 이상 이승에 네놈이 발붙일 자리는 없다.","JPN":"もうこの世にお前がいる場所はない。","ENG":"There is no place for you in this world anymore.","TWN":"現世已經沒有你的立足之地。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"늦지 않아서 다행입니다.","JPN":"手遅れにならずに済んで幸いでした。","ENG":"Thank goodness I wasn't late.","TWN":"幸好有趕上。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하야미 공…… 그렇게 다치신 몸으로…… 여기까지 오신 겁니까?","JPN":"速水殿……そんな体で……ここまで来られたのですか？","ENG":"Dame Sanae... Did you come all this way... in that state?","TWN":"速水……你自己也受傷……怎麼還跑到這裡來？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"걱정하실 정도는 아닙니다.","JPN":"ご心配には及びません。","ENG":"It is not as bad as it seems.","TWN":"不必擔心，沒那麼嚴重。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그나저나, 역귀가 된 자에게 다친 팔로 맞서다니 장하시군요.","JPN":"それより、疫鬼になった者に怪我した腕で立ち向かうとは、ご立派です。","ENG":"Anyway, it was impressive to see you fight against the Plagued Ghost with only one arm.","TWN":"倒是您竟然用受傷的手臂對付變成疫鬼之人，真是佩服。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……하바키가 놈들에게 당했습니다.","JPN":"……覇吐がやつらにやられました。","ENG":"...They killed Habaki.","TWN":"……幅木被那些傢伙擺了一道。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하바키는 미끼였을 뿐, 그들은 처음부터 영지의 결계옥을 노리고 있었습니다.","JPN":"覇吐は囮に過ぎず、彼らは最初から領地の結界玉を狙っていたのです。","ENG":"He was just bait. Their objective was to steal Akaitama.","TWN":"幅木只是煙霧彈，他們自始自終的目標都是領地的結界玉石。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"모두가 속은 셈이지요.","JPN":"みんなが騙されたわけですね。","ENG":"We were all fooled.","TWN":"大家都被他們騙了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님께선 두 분을 도우러 가셨을 텐데, 무사하신 겁니까?","JPN":"当主はお二人を助けに行かれたはずですが、ご無事ですか？","ENG":"Lady Nanahara went to help you two. Is everyone safe?","TWN":"堂主應該有去幫你們吧？她還好嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"방금 전에 연락이 닿았습니다. 당주님은 영지에서 기다리고 계실 겁니다.","JPN":"さっき連絡が取れました。ご当主様は領地でお待ちになっているはずです。","ENG":"We just made contact. She is waiting for us back home.","TWN":"剛才有聯絡上，堂主正在領地等候。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예? 놈들을 쫓아 결계옥을 되찾지 않는 겁니까?","JPN":"はい？　やつらを追いかけて結界玉を取り戻さないのですか？","ENG":"Huh? What about Akaitama? Don't we have to retrieve it?","TWN":"什麼？沒有追上去把結界玉石拿回來嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저희가 어디로 향하든, 그자들이 예견을 이용한다면 쉽게 찾아내진 못할 겁니다.","JPN":"私たちがどちらへ向かおうと、彼らが予言を利用するなら簡単には見つからないでしょう。","ENG":"Even if we tried, they have the power of foresight, and will not be easy to find.","TWN":"就算我們追上去，他們也可以利用預知的能力，要找到人恐怕不容易。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그러니 오히려 저희는 저희 방식대로 움직여서, 그들을 끌어들여야겠지요.","JPN":"ですのでむしろ私たちは私たちのやり方で動き、彼らを引き寄せるのです。","ENG":"Thus, we must move at our pace, and bring them to us.","TWN":"倒不如用照我們自己的方法行動，把他們引來。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};